-- Table structure for recipe
-- ----------------------------
DROP TABLE IF EXISTS `recipe`;
CREATE TABLE `recipe`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `addtime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `caipinmingcheng` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '菜品名称',
  `caixi` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '菜系',
  `tupian` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '图片',
  `caipinleixing` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '菜品类型',
  `cailiao` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '材料',
  `pengrenfangfa` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '烹饪方法',
  `sfsh` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '否' COMMENT '是否审核',
  `shhf` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '审核回复',
  `clicknum` int NULL DEFAULT 0 COMMENT '点击次数',
  `userid` bigint NOT NULL,
  `recipetype` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '来源类型（waiguomeishi/zhongshimeishi）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_recipe_recipetype`(`recipetype` ASC) USING BTREE,
  INDEX `idx_recipe_userid`(`userid` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3544366184484 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '菜谱表' ROW_FORMAT = DYNAMIC;

